CREATE OR REPLACE FUNCTION fpb_gos_get_payment_loan_date (as_conno text) RETURNS timestamp(0) AS $body$
DECLARE

ldt_date timestamp(0);

BEGIN

    select  max(sc_lon_m_loan_card_detail.loan_payment_date)
    into STRICT    ldt_date

    from    sc_lon_m_loan_card
            ,sc_lon_m_loan_card_detail
            ,(
              SELECT sc_lon_m_loan_card_detail.loan_contract_no as loan_contract_no
                    ,(sc_lon_m_loan_card_detail.payment_amount * sc_lon_m_ucf_loan_card_item.sign_status) as sum_a
                    ,sc_lon_m_ucf_loan_card_item.sign_status as sign_status
                    ,sc_lon_m_ucf_loan_card_item.item_type_code as item
              from sc_lon_m_loan_card_detail,sc_lon_m_ucf_loan_card_item
              where sc_lon_m_ucf_loan_card_item.item_type_code = sc_lon_m_loan_card_detail.item_type_code

              ) AA
    where   sc_lon_m_loan_card.loan_contract_no = sc_lon_m_loan_card_detail.loan_contract_no
    and     sc_lon_m_loan_card_detail.loan_contract_no = aa.loan_contract_no
    and     AA.SUM_A > 0
    and     sc_lon_m_loan_card.loan_contract_no = as_conno

;

  return ldt_date;
exception when others then CALL spa_dberror('fpb_gos_get_payment_loan_date');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
